/**
 * BOMIX Backend API Service
 *
 * This module provides a unified interface for all backend API calls.
 * It wraps Wails bindings and provides consistent error handling.
 */

// Import Wails generated bindings
// Note: These will be generated by Wails when the project is built
declare global {
  interface Window {
    go: {
      bomixAppBackendApp?: {
        // Series management
        CreateSeries(path: string, name: string, description: string): Promise<void>
        OpenSeries(path: string): Promise<void>
        CloseSeries(): Promise<void>
        GetSeriesInfo(): Promise<SeriesInfo>
        GetRecentSeries(): Promise<RecentFile[]>

        // Project management
        GetProjects(seriesId: number): Promise<Project[]>
        GetProject(id: number): Promise<Project>

        // Revision management
        GetRevisions(projectId: number): Promise<BomRevision[]>
        GetRevision(id: number): Promise<BomRevision>

        // Import/Export
        ImportExcel(filePaths: string[]): Promise<ImportResult[]>
        ExportExcel(options: ExportOptions): Promise<string[]>

        // Task management
        ListTasks(): Promise<Task[]>
        GetTask(id: string): Promise<Task>
        CancelTask(id: string): Promise<void>

        // Logs
        GetLogs(level: string, limit: number): Promise<LogEntry[]>
        ClearLogs(): Promise<void>

        // Settings
        GetSettings(): Promise<Settings>
        UpdateSettings(settings: Settings): Promise<void>

        // App
        Quit(): void
        GetVersion(): string
      }
      runtime?: {
        EventsOn: (eventName: string, callback: (data: any) => void) => void
        EventsOff: (eventName: string) => void
        EventsEmit: (eventName: string, data: any) => void
        OpenFileDialog: (options: FileDialogOptions) => Promise<string>
        SaveFileDialog: (options: FileDialogOptions) => Promise<string>
        CreateDirectoryDialog: (options: FileDialogOptions) => Promise<string>
        SelectFolderDialog: (options: FileDialogOptions) => Promise<string>
      }
    }
  }
}

