// Error handling wrapper
class ApiError extends Error {
  constructor(
    public message: string,
    public code: string = 'UNKNOWN_ERROR',
    public originalError?: Error
  ) {
    super(message)
    this.name = 'ApiError'
  }
}

// Handle API errors consistently
function handleApiError(error: unknown, context: string): never {
  if (error instanceof Error) {
    throw new ApiError(
      `${context}: ${error.message}`,
      'API_ERROR',
      error
    )
  }
  throw new ApiError(
    `${context}: Unknown error`,
    'UNKNOWN_ERROR'
  )
}

// Check if Wails bindings are available
function checkWailsBindings(): void {
  if (!window.go?.bomixAppBackendApp) {
    throw new ApiError(
      'Wails backend bindings not available. Make sure the application is running.',
      'NO_BACKEND'
    )
  }
}

// ==================== Series Management ====================

export async function CreateSeries(path: string, name: string, description: string): Promise<void> {
  try {
    checkWailsBindings()
    await window.go.bomixAppBackendApp!.CreateSeries(path, name, description)
  } catch (error) {
    handleApiError(error, 'CreateSeries')
  }
}

