// ==================== Event Listening ====================

const eventListeners = new Map<string, Set<(data: any) => void>>()

export function ListenToEvents(eventName: string, callback: (data: any) => void): void {
  try {
    if (!window.go?.runtime?.EventsOn) {
      console.warn('Wails runtime events not available')
      return
    }

    // Track listener
    if (!eventListeners.has(eventName)) {
      eventListeners.set(eventName, new Set())
    }
    eventListeners.get(eventName)!.add(callback)

    // Register with Wails
    window.go.runtime.EventsOn(eventName, (data: any) => {
      eventListeners.get(eventName)?.forEach(cb => cb(data))
    })
  } catch (error) {
    console.error(`Failed to listen to event ${eventName}:`, error)
  }
}

export function UnlistenToEvents(eventName: string): void {
  try {
    if (!window.go?.runtime?.EventsOff) {
      return
    }
    window.go.runtime.EventsOff(eventName)
    eventListeners.delete(eventName)
  } catch (error) {
    console.error(`Failed to unlisten to event ${eventName}:`, error)
  }
}

